    try {
      const { heading, subheading, type } = props;
      await notificationElem.open({
        heading,
        subheading,
        type,
      });
    } catch (error) {
      console.error(error);
    }
  };

  useEffect(() => {
    if (notificationElem) {
      setNotification(notificationElem);
    }
  }, [notificationElem]);

  return { notify };
};

